Trigger.script:
Yso = Yso or {} Yso._predict = Yso._predict or { last = 0 }
local now = (type(getEpoch)=="function" and getEpoch()) or os.time() if (now - (Yso._predict.last or 0)) < 5 then return end Yso._predict.last = now
-- NOTE: If you do not have a client-side 'curing predict' alias, the -- in-game command is typically: CURING AFFLICTIONS ADD <affliction>. send("curing predict brokenleftleg") send("curing predict brokenrightleg")

local who = matches[2] or "someone"

Yso       = Yso       or {}
Yso.occ   = Yso.occ   or {}
Yso.occ.aura = Yso.occ.aura or {}
Yso.occ.aura.cleansed = Yso.occ.aura.cleansed or {}

if Yso.occ.mark_cleansed then
  -- Server is telling us it's still clean, so refresh timestamp.
  Yso.occ.mark_cleansed(who)
end

deleteLine()
cecho(string.format(
  "<dark_orchid>[Occultism] <aquamarine>(ALREADY CLEANSED: %s).\n",
  who
))

local who = matches[2] or "someone"

Yso         = Yso         or {}
Yso.occ     = Yso.occ     or {}
Yso.occ.aura = Yso.occ.aura or {}
Yso.occ.aura.last_attempt = Yso.occ.aura.last_attempt or {}

local function _now()
  return (type(getEpoch) == "function" and getEpoch()) or os.time()
end

-- This line is the ATTEMPT line (not the success line).
Yso.occ.aura.last_attempt[who] = _now()

deleteLine()

cecho(string.format(
  "\n<dark_orchid>[Occultism] <gray>(CLEANSEAURA attempt on %s).<reset>\n",
  who
))
resetFormat()

local who = matches[2] or "someone"

Yso       = Yso       or {}
Yso.occ   = Yso.occ   or {}
Yso.occ.aura          = Yso.occ.aura          or {}
Yso.occ.aura.cleansed = Yso.occ.aura.cleansed or {}

if Yso.occ.mark_aura_restored then
  Yso.occ.mark_aura_restored(who)
else
  -- fall back: just clear the entry
  Yso.occ.aura.cleansed[who] = nil
end

deleteLine()
cecho(string.format(
  "<dark_orchid>[Occultism] <yellow>(AURA RESTORED on %s).\n",
  who
))

Yso = Yso or {}
Yso.occ = Yso.occ or {}
Yso.occ.aeon = Yso.occ.aeon or {}

local who = matches[2] or ""
if who ~= "" and Yso.occ and Yso.occ.aeon and type(Yso.occ.aeon.on_sip) == "function" then
  Yso.occ.aeon.on_sip(who)
end

Yso = Yso or {}
Yso.dom = Yso.dom or {}
Yso.dom.pathfinder = Yso.dom.pathfinder or {}

if type(Yso.dom.pathfinder_set_ready) == "function" then
  Yso.dom.pathfinder_set_ready(true, "summoned")
else
  Yso.dom.pathfinder.ready = true
  Yso.dom.pathfinder.last_summon_ts = (type(getEpoch) == "function") and getEpoch() or os.time()
end

Yso = Yso or {}
Yso.dom = Yso.dom or {}
Yso.dom.pathfinder = Yso.dom.pathfinder or {}

if type(Yso.dom.pathfinder_set_ready) == "function" then
  Yso.dom.pathfinder_set_ready(false, "depleted")
else
  Yso.dom.pathfinder.ready = false
end

Yso = Yso or {}
Yso.dom = Yso.dom or {}
Yso.dom.pathfinder = Yso.dom.pathfinder or {}

if type(Yso.dom.pathfinder_set_ready) == "function" then
  Yso.dom.pathfinder_set_ready(false, "home_fail")
else
  Yso.dom.pathfinder.ready = false
end

Alias.script:
Yso = Yso or {}
Yso.off = Yso.off or {}
Yso.off.oc = Yso.off.oc or {}

local AB = Yso.off.oc.occ_aff_burst
if AB and type(AB.automation_toggle) == "function" then
  AB.automation_toggle()
elseif type(cecho) == "function" then
  cecho("<red>[YSO] <reset>occ_aff_burst automation module not loaded.\n")
end

local y = rawget(_G, "Yso")
if type(y) ~= "table" then
  y = {}
  _G.Yso = y
end

local ok_devil_active = (y.tarot and type(y.tarot.devil_active) == "function")
local ok_devil_up     = (y.tarot and type(y.tarot.devil_up) == "function")
local ok_devil_down   = (y.tarot and type(y.tarot.devil_down) == "function")

local ok_helper =
  (y.occ and y.occ.unravel
   and type(y.occ.unravel.enlighten_cmd) == "function"
   and type(y.occ.unravel.unravel_cmd) == "function"
   and type(y.occ.unravel.minion_unravel_cmd) == "function")

local ok_devil_moon = (y.occ and type(y.occ.devil_moon_cmd) == "function")

local ok_off =
  (y.off and y.off.oc
   and type(y.off.oc.toggle) == "function"
   and type(y.off.oc.attack) == "function"
   and type(y.off.oc.tick) == "function")

echo("\n[YSO DIAG] Devil tracker:\n")
echo("  devil_active(): " .. (ok_devil_active and "OK" or "MISSING") .. "\n")
echo("  devil_up():     " .. (ok_devil_up     and "OK" or "MISSING") .. "\n")
echo("  devil_down():   " .. (ok_devil_down   and "OK" or "MISSING") .. "\n")

echo("[YSO DIAG] Unravel helper:\n")
echo("  enlighten_cmd():      " .. (ok_helper and "OK" or "MISSING") .. "\n")
echo("  devil_moon_cmd():     " .. (ok_devil_moon and "OK" or "MISSING") .. "\n")

echo("[YSO DIAG] Offense:\n")
echo("  Off.toggle/attack/tick: " .. (ok_off and "OK" or "MISSING") .. "\n\n")

Yso = Yso or {} Yso.fool = Yso.fool or {}
if Yso.fool.mark_diag_pending then Yso.fool.mark_diag_pending() else -- fallback if module isnÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢t loaded yet Yso.fool.state = Yso.fool.state or {} Yso.fool.state.await_diag = true end
local Q = (Yso and Yso.queue) if Q and type(Q.addclearfull) == "function" then Q.addclearfull("e", "diagnose") else if Yso.queue and type(Yso.queue.eq_clear)=="function" then Yso.queue.eq_clear("diagnose") else if type(send)=="function" then send("diagnose") end end end

Script.script:
--========================================================--
-- Yso_Occultist_Affmap.lua  (DROP-IN)  [UPDATED]
-- Skill â†’ affliction/effect map for Occultism / Tarot / Domination
-- Notes:
--   â€¢ â€œaffsâ€ are canonical keys you should track.
--   â€¢ AK limb state is tracked as: leftarm/rightarm/leftleg/rightleg (tiered 100/200/300),
--     NOT left_arm_broken style keys.
--========================================================--

Yso        = Yso        or {}
Yso.oc     = Yso.oc     or {}
Yso.oc.map = Yso.oc.map or {}

local M = Yso.oc.map

M.skills = M.skills or {
  occultism = {
    instill = {
      affs  = { "asthma", "clumsiness", "healthleech", "sensitivity", "slickness", "paralysis", "darkshade" },
      notes = "Selectable: INSTILL <tgt> WITH <affliction>.",
    },

    -- SHRIVEL (direct limb pressure; AK tracks limb state as leftarm/rightarm/leftleg/rightleg tiers)
    shrivel = {
      affs    = { "leftarm", "rightarm", "leftleg", "rightleg" },
      effects = { "limb_damage" },
      notes   = "SHRIVEL <left/right> <arm/leg> <tgt> (EQ). Progresses limb state; AK models limbs as tiered scores.",
    },

    whisperingmadness = {
      affs  = { "whisperingmadness" },
      notes = "Requires at least one insanity from the WHISPERINGMADNESS eligibility list.",
    },

    truename_utter = {
      affs  = { "aeon" },
      notes = "UTTER TRUENAME <tgt> applies aeon (separate source from tarot AEON).",
    },

    chaosrays = {
      affs  = { "random_ray" },
      notes = "Seven Rays: random ray effects to everyone in-room except caster.",
    },

    bodywarp = {
      effects = { "limb_damage" },
      notes   = "BODYWARP can optionally combine one of: ague / shrivel / regress (lesser works).",
    },

    regress = {
      effects = { "prone_target" },
      affs    = { "anorexia" },
      notes   = "REGRESS <tgt> (EQ). If target is not prone, prones them. If already prone, applies anorexia.",
    },

    compel_discord = {
      reqs  = { "healthleech", "asthma" },
      affs  = { "loneliness", "dizziness" },
      notes = "COMPEL Discord result.",
    },

    compel_entropy = {
      reqs    = { "haemophilia", "addiction" },
      effects = { "strip_speed_if_present" },
      affs    = { "aeon_if_no_speed" },
      notes   = "COMPEL Entropy result.",
    },

    compel_potential = {
      reqs    = { "frozen_or_4broken" },
      affs    = { "blackout_if_4broken" },
      effects = { "damage_if_frozen" },
      notes   = "COMPEL Potential result.",
    },

    ague = {
      affs  = { "frozen" },
      notes = "Ague is the frozen line (terminal key frozen).",
    },
  },

  tarot = {
    moon = {
      affs  = { "stupidity", "epilepsy", "confusion", "hallucinations", "claustrophobia", "agoraphobia", "masochism", "hypersomnia" },
      notes = "Moon supports directed affliction selection; offense uses Moon for specific affs.",
    },

    aeon = {
      affs  = { "aeon" },
      notes = "Tarot AEON card fling source.",
    },

    lovers = {
      affs  = { "lovers" },
      notes = "In-love state.",
    },

    ruinate_lovers = {
      affs  = { "manaleech" },
      notes = "RUINATE LOVERS <tgt> (BAL). Primary manaleech source for mana route.",
    },

    ruinate_justice = {
      effects = { "convert_affs_to_limb_progress", "frozen_if_threshold", "prone_if_both_legs_progressed" },
      affs    = { "leftarm", "rightarm", "leftleg", "rightleg" },
      notes   = "RUINATE JUSTICE <tgt> (BAL). AK/Legacy treat Justice as limb progress conversion; use AK limb keys.",
    },

    ruinate_wheel = {
      spins = {
        [1] = { affs = { "frozen" } },
        [2] = { affs = { "stuttering" } },
        [3] = { affs = { "blackout" } },
        [4] = { affs = { "UNKNOWN" } },
        [5] = { affs = { "UNKNOWN" } },
        [6] = { affs = { "UNKNOWN" } },
        [7] = { affs = { "aeon" }, effects = { "strip_speed_all" } },
      },
      notes = "Per your report: 7 spins => aeon + strips speed to all. 4â€“6 TBD.",
    },
  },

  domination = {
    bubonis = {
      affs      = { "asthma" },
      followups = { asthma = { "slickness" } },
      notes     = "Entity. If target already has asthma, Bubonis follow-up applies slickness.",
    },

    danaeus_storm = {
      affs  = { "clumsiness" },
      notes = "Entity. Syntax: COMMAND STORM AT <tgt>.",
    },

    nemesis_humbug = {
      affs  = { "addiction" },
      notes = "Entity. Humbug curse => addiction.",
    },

    scrag_bloodleech = {
      affs  = { "haemophilia" },
      notes = "Entity. Bloodleech => haemophilia.",
    },

    palpatar_worm = {
      affs  = { "healthleech" },
      prime = { affs = { "nausea" } },
      notes = "Entity. Worm => healthleech; primebond may add nausea.",
    },

    lycantha_hound = {
      affs  = { "weariness" },
      notes = "Entity. Hound => weariness.",
    },

    -- CRONE (Hecate) limb pressure (AK limb keys)
    hecate_crone = {
      affs    = { "leftarm", "rightarm", "leftleg", "rightleg" },
      effects = { "limb_damage" },
      notes   = "Entity. COMMAND CRONE AT <tgt> <left/right> <arm/leg>. Use with SHRIVEL for guaranteed limb progress.",
    },

    eerion_gremlin_prime = {
      affs    = { "dizziness" },
      effects = { "knock_off_balance_if_already_dizzy" },
      notes   = "Entity primebond => dizziness and can off-balance.",
    },

    pyradius_firelord = {
      converts = {
        whisperingmadness = "recklessness",
        manaleech         = "anorexia",
      },
      effects = { "healthleech_becomes_psychic_damage" },
      notes   = "Firelord conversions: manaleech -> anorexia (avoid if you do NOT want to convert manaleech).",
    },
  },
}

function M.rebuild_by_aff()
  M.by_aff = {}

  local function add(aff, src)
    if not aff or aff == "" then return end
    M.by_aff[aff] = M.by_aff[aff] or {}
    M.by_aff[aff][src] = true
  end

  for school, abilities in pairs(M.skills) do
    for key, node in pairs(abilities) do
      local src = school .. "." .. key

      if node.affs then
        for _, a in ipairs(node.affs) do add(a, src) end
      end

      if key == "ruinate_wheel" and node.spins then
        for spin, s in pairs(node.spins) do
          if s.affs then
            for _, a in ipairs(s.affs) do add(a, src .. ".spin" .. tostring(spin)) end
          end
        end
      end

      if node.converts then
        for from, to in pairs(node.converts) do
          add(to, src .. ".convert(" .. from .. ")")
        end
      end

      if node.followups and node.followups.asthma then
        for _, a in ipairs(node.followups.asthma) do
          add(a, src .. ".followup(asthma)")
        end
      end

      if node.prime and node.prime.affs then
        for _, a in ipairs(node.prime.affs) do
          add(a, src .. ".prime")
        end
      end
    end
  end
end

M.rebuild_by_aff()
--========================================================--

return M

--========================================================-- -- Yso.state wiring (DEPRECATED) -- -- NOTE: -- GMCP Char.Vitals plumbing is now centralized in: -- ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ Yso.pulse (wake bus) -> calls Yso.ingest.vitals(v,"gmcp") -- -- This stub remains only to kill any legacy handler IDs. --========================================================--
Yso = Yso or {} Yso._eh = Yso._eh or {}
if Yso._eh.vitals then pcall(killAnonymousEventHandler, Yso._eh.vitals) Yso._eh.vitals = nil end

-- Auto-exported from Mudlet package script: Prio Baselines
-- DO NOT EDIT IN XML; edit this file instead.

Legacy = Legacy or {}
Legacy.Curing = Legacy.Curing or {}
Legacy.Curing.Prios = Legacy.Curing.Prios or {}

-- Cache of baselines keyed by server-side prio set name (dwc, snb, etc).
Legacy.Curing.Prios.baseSets = Legacy.Curing.Prios.baseSets or {}
Legacy.Curing.Prios.capture  = Legacy.Curing.Prios.capture  or { active=false, set=nil, lastPrio=nil }

-- Track what we believe is active server-side.
Legacy.Curing.ActiveServerSet = Legacy.Curing.ActiveServerSet or "legacy"

-- NOTE: Legacy.Curing.SwitchServerSet is defined in cureset_baselines.lua (SSOT).

-- Point Legacy's "Reprio baseline" at the active set's stored baseline.
function Legacy.Curing.UseBaseline(set)
  set = (set or Legacy.Curing.ActiveServerSet or "legacy"):lower()
  if not Legacy.Curing.Prios.baseSets[set] then return false end
  Legacy.Curing.Prios.legacy = Legacy.Curing.Prios.baseSets[set]
  Legacy.Curing.Prios.temp   = table.deepcopy(Legacy.Curing.Prios.legacy)
  return true
end

-- Auto-exported from Mudlet package script: Cureset Baselines -- DO NOT EDIT IN XML; edit this file instead.
Legacy = Legacy or {} Legacy.Curing = Legacy.Curing or {} Legacy.Curing.Prios = Legacy.Curing.Prios or {}
Legacy.Curing.ActiveServerSet = Legacy.Curing.ActiveServerSet or "legacy" Legacy.Curing.Prios.baseSets = Legacy.Curing.Prios.baseSets or {} Legacy.Curing.Prios.capture = Legacy.Curing.Prios.capture or { active=false, set=nil, lastPrio=nil }
function Legacy.Curing.Prios.UseBaseline(set) set = (set or Legacy.Curing.ActiveServerSet or "legacy"):lower() local base = Legacy.Curing.Prios.baseSets[set] if not base then return false end
-- This is what Reprio() uses as â€œdefaultâ€ Legacy.Curing.Prios.legacy = base return true end
function Legacy.Curing.SwitchServerSet(set) set = (set or "legacy"):lower() local changed = (Legacy.Curing.ActiveServerSet ~= set)
if changed then Legacy.Curing.ActiveServerSet = set send("curingset switch " .. set) end
-- If we don't have a baseline cached for this set, pull it once. if not Legacy.Curing.Prios.baseSets[set] then tempTimer(0.2, function() send("curing priority list") end) else -- Apply baseline only when transitioning, or if legacy baseline isn't already pointing at this base set. if changed or Legacy.Curing.Prios.legacy ~= Legacy.Curing.Prios.baseSets[set] then Legacy.Curing.Prios.UseBaseline(set) end end end

-- Auto-exported from Mudlet package script: Yso_Alert_Radiance helper -- DO NOT EDIT IN XML; edit this file instead.
-- Radiance alert helper (used by triggers below) Yso = Yso or {} Yso.radianceAlert = Yso.radianceAlert or {}
Yso.radianceAlert.cfg = Yso.radianceAlert.cfg or { SOUND = "C:/Windows/Media/Alarm01.wav", WIDTH = 80, PAD_BEFORE = 1, PAD_AFTER = 1, }
function Yso.radianceAlert.center(line) local w = Yso.radianceAlert.cfg.WIDTH or 80 line = tostring(line or "") if #line >= w then return line end local pad = math.floor((w - #line) / 2) if pad < 0 then pad = 0 end return string.rep(" ", pad) .. line end
function Yso.radianceAlert.sound() local file = Yso.radianceAlert.cfg.SOUND or "" if file == "" then return end if type(playSoundFile) == "function" then pcall(playSoundFile, file) elseif type(playSound) == "function" then pcall(playSound, file) end end
function Yso.radianceAlert.banner(lines, color) local cfg = Yso.radianceAlert.cfg color = color or "<red>" tempTimer(0, function() for _=1,(cfg.PAD_BEFORE or 0) do cecho("\n") end for _,ln in ipairs(lines) do cecho(color .. Yso.radianceAlert.center(ln) .. "\n") end for _=1,(cfg.PAD_AFTER or 0) do cecho("\n") end end) end

-- Auto-exported from Mudlet package script: Occultism reference -- DO NOT EDIT IN XML; edit this file instead.
--========================================================-- -- yso_occultist_occultism_ref.lua -- Occultist: Occultism skill reference for Achaea (Yso project) -- â€¢ Pure data + tiny helpers, no Mudlet dependencies. -- â€¢ Intentionally conservative: only claims specific mechanics -- where we have AB text/screens; everything else is fuzzy/meta. -- â€¢ Use this as a central reference table for offense logic, UI, -- docs, etc. --========================================================--
Yso = Yso or {} Yso.occultist = Yso.occultist or {}
local O = {}
---------------------------------------------------------------------- -- CORE FORMAT NOTE -- Each skill uses: -- key = lowercase name (no spaces) -- name = in-game name -- syntax = string or {strings} -- target = "enemy" | "ally" | "room" | "self" | "enemy-limb" | etc. -- works_on = rough AB "Works on/against" text -- queue_flag = "eq" | "bal" | "eqbal" | "free" | "full" (planning hint) -- bal_type = "equilibrium" | "balance" | "eqbal" -- eq_cost = seconds of equilibrium (when known) -- mana_cost / karma_cost / willpower_cost = basic resources (when known) -- role = { tags like "offense","limb-core","instakill","utility" } -- summary = short scripting-oriented description -- tags = arbitrary extra classification -- requirements/effects/synergy/flags = extra structured info ----------------------------------------------------------------------
---------------------------------------------------------------------- -- AGUE ---------------------------------------------------------------------- O.ague = { skillset = "Occultism", name = "Ague", syntax = "AGUE <target>", target = "enemy", works_on = "adventurers", queue_flag = "eq", bal_type = "equilibrium", eq_cost = 2.20, mana_cost = 100, role = {"offense", "setup"}, summary = "Multi-stage cold: burns caloric, then applies shivering (eq loss over time) and can escalate to full freeze; double-freezes if two limbs require resto.", tags = {"freeze", "anti-caloric", "eq-drain", "limb-synergy"}, effects = { stages = {"strip_caloric", "shivering", "full_freeze"}, }, }
---------------------------------------------------------------------- -- AURAGLANCE ---------------------------------------------------------------------- O.auraglance = { skillset = "Occultism", name = "Auraglance", syntax = "AURAGLANCE <target>", target = "enemy", works_on = "adventurers", queue_flag = "eq", bal_type = "equilibrium", eq_cost = 1.00, mana_cost = 20, role = {"utility", "intel"}, summary = "Locate the current position of someone by sensing their aura.", tags = {"locate", "tracking"}, }
---------------------------------------------------------------------- -- WARP (basic single-target damage) ---------------------------------------------------------------------- O.warp = { skillset = "Occultism", name = "Warp", syntax = "WARP <target>", target = "enemy", works_on = "adventurers+denizens", queue_flag = "eq", bal_type = "equilibrium", eq_cost = 4.00, mana_cost = 80, role = {"offense", "damage-core"}, summary = "Bread-and-butter single-target damage: warp the victim's body with lethal mutations.", tags = {"damage", "pve", "single-target"}, }
---------------------------------------------------------------------- -- NIGHT ---------------------------------------------------------------------- O.night = { skillset = "Occultism", name = "Night", syntax = "NIGHT", target = "room", queue_flag = "eq", bal_type = "equilibrium", role = {"utility", "defense"}, summary = "Shroud the room in magical darkness.", tags = {"darkness", "room-control"}, }
---------------------------------------------------------------------- -- SHROUD ---------------------------------------------------------------------- O.shroud = { skillset = "Occultism", name = "Shroud", syntax = "SHROUD", target = "self", queue_flag = "eq", bal_type = "equilibrium", role = {"utility", "defense"}, summary = "Conceal your subsequent actions from obvious observation.", tags = {"stealth"}, }
---------------------------------------------------------------------- -- BODYWARP (two modes: self-fear + limb/lesser works) ---------------------------------------------------------------------- O.bodywarp = { skillset = "Occultism", name = "Bodywarp", syntax = { "BODYWARP", "BODYWARP <target> <limb> [lesser occultic work]", }, works_on = "adventurers", queue_flag = "eq", bal_type = "equilibrium", variants = { self_fear = { mode = "self_fear", target = "room", eq_cost = 4.00, mana_cost = 75, role = {"offense", "control"}, summary = "Warp your form into an unspeakable horror, causing primal fear in those who can see you.", tags = {"room-aoe", "fear", "vision-dependent"}, requirements = { victim_unblind = true }, }, limb = { mode = "limb", target = "enemy-limb", eq_cost = 2.60, mana_cost = 50, willpower_cost= 2, role = {"offense", "limb-core"}, summary = "Mutate a specific limb, dealing limb + minor HP damage; bonus damage if already broken. Can fuse in a lesser occultic work.", tags = {"limb-damage", "limb-finisher"}, lesser_works = {"ague", "shrivel", "regress"}, }, }, role = {"offense", "limb-core", "control"}, summary = "Umbrella for BODYWARP modes; see .variants.self_fear and .variants.limb.", tags = {"multi-mode"}, }
---------------------------------------------------------------------- -- ELDRITCHMISTS ---------------------------------------------------------------------- O.eldritchmists = { skillset = "Occultism", name = "Eldritchmists", syntax = "ELDRITCHMISTS", target = "room", works_on = "room", queue_flag = "eq", bal_type = "equilibrium", eq_cost = 4.00, mana_cost = 200, role = {"offense", "aoe"}, summary = "Call up eldritch mists that damage all other adventurers present.", tags = {"room-aoe", "damage"}, }
---------------------------------------------------------------------- -- MASK ---------------------------------------------------------------------- O.mask = { skillset = "Occultism", name = "Mask", syntax = "MASK", target = "self", queue_flag = "eq", bal_type = "equilibrium", role = {"utility", "defense"}, summary = "Conceal the movements or presence of your Chaos entities.", tags = {"entity", "stealth"}, }
---------------------------------------------------------------------- -- ATTEND ---------------------------------------------------------------------- O.attend = { skillset = "Occultism", name = "Attend", syntax = "ATTEND <target>", target = "ally", works_on = "adventurers", queue_flag = "eq", bal_type = "equilibrium", eq_cost = 2.20, mana_cost = 125, role = {"support", "defense"}, summary = "Force your student to attend to you, curing deafness and blindness.", tags = {"cure-blind", "cure-deaf", "ally-support"}, effects = { cures = {"blindness","deafness"} }, }
