-- Return a skill table by (case-insensitive) key. function Yso.occultist.getOccultismSkill(name) if not name then return nil end name = string.lower(name) return O[name] end
-- Check if a given Occultism skill should be treated as part of -- *normal* offense (honours flags like include_in_offense=false). function Yso.occultist.isOccultismOffense(name) local s = Yso.occultist.getOccultismSkill(name) if not s then return false end local roles = s.role or {} local hasOffense = false for _,r in ipairs(roles) do if r == "offense" then hasOffense = true break end end if not hasOffense then return false end if s.flags and s.flags.include_in_offense == false then return false end return true end
-- List all Occultism skills containing the given role tag. function Yso.occultist.listOccultismByRole(role) local out = {} for k,v in pairs(O) do if v.role then for _,r in ipairs(v.role) do if r == role then table.insert(out, k) break end end end end table.sort(out) return out end
