--==================================================================-- -- Helper accessors --==================================================================--
--- Get Domination entry by short key (e.g. "scrag", "worm", "glaaki"). function Yso.occ.getDom(key) if not key then return nil end key = key:lower() return D[key] end
--- Get Domination entry by ABADMIN id. function Yso.occ.getDomById(id) if not id then return nil end for _, v in pairs(D) do if v.id == id then return v end end return nil end
--- List all Domination entities, optionally filtered by role. function Yso.occ.listDomByRole(role) local out = {} for k, v in pairs(D) do if not role then table.insert(out, k) elseif v.roles then for _, r in ipairs(v.roles) do if r == role then table.insert(out, k) break end end end end table.sort(out) return out end
--- Get Domination entry by canonical route-entity key (e.g. "worm", "storm", "slime"). function Yso.occ.getDomByEntity(entity) if not entity then return nil end local map = { worm = "worm", storm = "danaeus", slime = "ninkharsag", sycophant = "rixil", humbug = "nemesis", firelord = "pyradius", } local key = tostring(entity or ""):lower() return Yso.occ.getDom(map[key] or key) end
--- Get a best-effort lowercase pact/bond name for an entity. function Yso.occ.getDomBondName(entity) local d = Yso.occ.getDomByEntity(entity) return d and tostring(d.name or entity or ""):lower() or tostring(entity or ""):lower() end
do local count = 0 for _ in pairs(D) do count = count + 1 end if cecho then cecho(string.format( "<green>[Yso] Occultist Domination reference loaded (%d entities).\n", count )) end end
